+/**
+ * Gets protected ranges for the supplied rule. A null rule protects only marker
+ * lines plus ranges disabled for every rule (used by custom replacements).
+ */
+export function getLintMarkerRanges(text: string, ruleAlias: string | null): {startIndex: number, endIndex: number}[] {
+  const markers = getLintMarkers(text);
+  if (markers.length === 0) {
+    return [];
+  }
+
+  const markersByLine = new Map<number, LintMarker>();
+  for (const marker of markers) {
+    markersByLine.set(marker.line, marker);
+  }
+
+  const lines = text.split('\
');
+  const scopes: DisableScope[] = [];
+  const lineDisables: {remaining: number, all: boolean, rules: Set<string>}[] = [];
+  const ranges: {startIndex: number, endIndex: number}[] = [];
+  let offset = 0;
+
+  for (let line = 0; line < lines.length; line++) {
+    const lineEnd = offset + lines[line].length + (line < lines.length - 1 ? 1 : 0);
+    const marker = markersByLine.get(line);
+    const disabled = isRuleDisabled(scopes, lineDisables, ruleAlias);
+    if (marker || disabled) {
+      ranges.push({startIndex: offset, endIndex: lineEnd});
+    }
+
+    if (marker) {
+      if (marker.command === 'disable') {
+        scopes.push(makeScope(marker.rules));
+      } else if (marker.command === 'enable') {
+        enableRules(scopes, marker.rules);
+      } else if (marker.lineCount && line < lines.length - 1) {
+        lineDisables.push({remaining: marker.lineCount, ...makeScope(marker.rules)});
+      }
+    }
+
+    for (let index = lineDisables.length - 1; index >= 0; index--) {
+      lineDisables[index].remaining--;
+      if (lineDisables[index].remaining === 0) {
+        lineDisables.splice(index, 1);
+      }
+    }
+    offset = lineEnd;
+  }
+
+  return mergeRanges(ranges);
+}
+
+function getLintMarkers(text: string): LintMarker[] {
+  const restrictedRanges = getRestrictedMarkerRanges(text);
+  const knownRules = new Set<string>();
+  // Importing rules here would introduce a circular dependency. Rule aliases are
+  // normalized by the caller-independent registry via the global rule list.
+  for (const rule of require('../rules').rules as {alias: string}[]) {
+    knownRules.add(rule.alias.toLowerCase());
+  }
+  const markers: LintMarker[] = [];
+  let offset = 0;
+  for (const [line, value] of text.split('\
').entries()) {
+    const endIndex = offset + value.length + (line < text.split('\
').length - 1 ? 1 : 0);
+    if (!isInRanges(offset, endIndex, restrictedRanges)) {
+      const marker = parseLintMarker(value, knownRules);
+      if (marker) {
+        markers.push({...marker, line, startIndex: offset, endIndex});
+      }
+    }
+    offset = endIndex;
+  }
+  return markers;
+}
+
+function getRestrictedMarkerRanges(text: string): {startIndex: number, endIndex: number}[] {
+  const ranges: {startIndex: number, endIndex: number}[] = [];
+  for (const type of [MDAstTypes.Code, MDAstTypes.InlineCode, MDAstTypes.Math, MDAstTypes.InlineMath]) {
+    for (const position of getPositions(type, text)) {
+      ranges.push({startIndex: position.start.offset, endIndex: position.end.offset});
+    }
+  }
+  const yaml = text.match(/^---\
[\\s\\S]*?\
---(?=\
|$)/);
+  if (yaml?.index === 0) {
+    ranges.push({startIndex: 0, endIndex: yaml[0].length});
+  }
+  return ranges;
+}
+
+function parseLintMarker(line: string, knownRules: Set<string>): Omit<LintMarker, 'line' | 'startIndex' | 'endIndex'> | null {
+  const html = line.match(/^[ \	]*<!--\\s*(.*?)\\s*-->[ \	]*$/);
+  const obsidian = line.match(/^[ \	]*%%\\s*(.*?)\\s*%%[ \	]*$/);
+  const body = html?.[1] ?? obsidian?.[1];
+  if (body === undefined) {
+    return null;
+  }
+  const nextN = body.match(/^linter-disable-next-n-lines\\s*:\\s*(\\S+)(?:\\s+(.*))?$/i);
+  if (nextN) {
+    const count = /^(?:[1-9]\\d*)$/.test(nextN[1]) ? Number(nextN[1]) : 0;
+    return {command: 'next-n-lines', rules: normalizeRules(nextN[2], knownRules), lineCount: count};
+  }
+  const normal = body.match(/^linter-(disable-next-line|disable|enable)(?:\\s+(.*))?$/i);
+  if (!normal) {
+    return null;
+  }
+  return {
+    command: normal[1].toLowerCase() === 'disable' ? 'disable' : normal[1].toLowerCase() === 'enable' ? 'enable' : 'next-line',
+    rules: normalizeRules(normal[2], knownRules),
+    lineCount: normal[1].toLowerCase() === 'disable-next-line' ? 1 : undefined,
+  };
+}
+
+function normalizeRules(ruleList: string | undefined, knownRules: Set<string>): string[] | null {
+  if (ruleList === undefined) {
+    return null;
+  }
+  return [...new Set(ruleList.split(',').map((rule) => rule.trim().toLowerCase()).filter((rule) => knownRules.has(rule)))];
+}
+
+function makeScope(ruleList: string[] | null): DisableScope {
+  return ruleList === null ? {all: true, rules: new Set(), enabledRules: new Set()} : {all: false, rules: new Set(ruleList), enabledRules: new Set()};
+}
+
+function isRuleDisabled(scopes: DisableScope[], lineDisables: {all: boolean, rules: Set<string>}[], ruleAlias: string | null): boolean {
+  return [...scopes, ...lineDisables].some((scope) => scope.all ? ruleAlias !== null && !scope.enabledRules?.has(ruleAlias) : ruleAlias !== null && scope.rules.has(ruleAlias));
+}
+
+function enableRules(scopes: DisableScope[], rules: string[] | null): void {
+  if (rules === null) {
+    scopes.pop();
+    return;
+  }
+  for (const rule of rules) {
+    for (let index = scopes.length - 1; index >= 0; index--) {
+      const scope = scopes[index];
+      if (scope.all && !scope.enabledRules.has(rule)) {
+        scope.enabledRules.add(rule);
+        break;
+      }
+      if (!scope.all && scope.rules.has(rule)) {
+        scope.rules.delete(rule);
+        if (scope.rules.size === 0) {
+          scopes.splice(index, 1);
+        }
+        break;
+      }
+    }
+  }
+}
+
+function isInRanges(startIndex: number, endIndex: number, ranges: {startIndex: number, endIndex: number}[]): boolean {
+  return ranges.some((range) => startIndex < range.endIndex && endIndex > range.startIndex);
+}
+
+function mergeRanges(ranges: {startIndex: number, endIndex: number}[]): {startIndex: number, endIndex: number}[] {
+  return ranges.reduce((merged, range) => {
+    const previous = merged[merged.length - 1];
+    if (previous && range.startIndex <= previous.endIndex) {
+      previous.endIndex = Math.max(previous.endIndex, range.endIndex);
+    } else {
+      merged.push({...range});
+    }
+    return merged;
+  }, [] as {startIndex: number, endIndex: number}[]);
+}
